Your task is to write a Jest test case that exposes a specific mutation in a JavaScript/TypeScript project.

MUTATION DETAILS
The mutation affects the following file:
pull.js
Here is the full content of that file (shown with a <PLACEHOLDER> marker):
'use strict'

module.exports = function pull (a) {
  var length = arguments.length
  if (typeof a === 'function' && a.length === 1) {
    var args = new Array(length)
    for(var i = 0; i < length; i++)
      args[i] = arguments[i]
    return function (read) {
      if (args == null) {
        throw new TypeError("partial sink should only be called once!")
      }

      // Grab the reference after the check, because it's always an array now
      // (engines like that kind of consistency).
      var ref = args
      args = null

      // Prioritize common case of small number of pulls.
      switch (length) {
      case 1: return pull(read, ref[0])
      case 2: return pull(read, ref[0], ref[1])
      case 3: return pull(read, ref[0], ref[1], ref[2])
      case 4: return pull(read, ref[0], ref[1], ref[2], ref[3])
      default:
        ref.unshift(read)
        return pull.apply(null, ref)
      }
    }
  }

  var read = a

  if (read && typeof read.source === 'function') {
    read = read.source
  }

  for (var i = 1; i < length; i++) {
    var s = arguments[i]
    if (typeof s === 'function') {
      read = s(read)
       <PLACEHOLDER>

      s.sink(read)
      read = s.source
    }
  }

  return read
}

In the original code, <PLACEHOLDER> has the value:

-       } else if (s && typeof s === 'object') {
In the mutated code, <PLACEHOLDER> has the value:

+       } else if (false) {


YOUR TASK
Write one Jest test file that:
    1. Passes when run against the original code.
    2. Fails when run against the mutated code.
    3. Tests the behavior of the mutated file in a way that reliably detects the mutation.
The test will be saved at the following path, relative to this test-generation project’s root:
llm-cache/anthropic_claude-sonnet-4.6/temp_0.5/withoutTests/cached/artifacts/pull-stream/attempt_1/pending_category/mutant-81370fe/testCase.test.ts

ALLOWED LIBRARIES
You may use:
    1. Any built-in Node.js modules (e.g., fs, path, crypto, etc.).

You may not use any other third-party libraries.

Looking at the mutation, the change is from:
```javascript
} else if (s && typeof s === 'object') {
```
to:
```javascript
} else if (false) {
```

This means the branch that handles "through" streams (objects with both `.sink` and `.source` properties) will never execute. When a through stream (duplex/transform) is passed as an argument, the code that calls `s.sink(read)` and sets `read = s.source` will be skipped.

I need to create a test that uses a through stream object (with `sink` and `source` properties) and verifies it processes data correctly.

```typescript
import pull from "../../../../../../../../../../../subject_repositories/pull-stream/pull.js"

describe("pull with through stream objects", () => {
  it("should correctly pipe through a duplex stream object with sink and source properties", (done) => {
    const results: number[] = [];

    // Create a simple source that emits values 1, 2, 3
    function source(end: boolean | null, cb: (end: boolean | null, data?: number) => void) {
      let i = 0;
      const values = [1, 2, 3];
      return function read(end: boolean | null, cb: (end: boolean | null, data?: number) => void) {
        if (end) return cb(end);
        if (i >= values.length) return cb(true);
        cb(null, values[i++]);
      };
    }

    // Create a through stream as an object with sink and source
    function createThrough(transform: (x: number) => number) {
      let _read: Function;

      const through = {
        sink: function(read: Function) {
          _read = read;
        },
        source: function(end: boolean | null, cb: (end: boolean | null, data?: number) => void) {
          _read(end, function(end: boolean | null, data?: number) {
            if (end) return cb(end);
            cb(null, transform(data!));
          });
        }
      };

      return through;
    }

    // Create a sink that collects results
    function sink(read: Function) {
      function next() {
        read(null, function(end: boolean | null, data?: number) {
          if (end === true) {
            // Verify results
            expect(results).toEqual([2, 4, 6]);
            done();
            return;
          }
          if (end) {
            done(end);
            return;
          }
          results.push(data!);
          next();
        });
      }
      next();
    }

    // Create source stream
    const sourceStream = (function() {
      let i = 0;
      const values = [1, 2, 3];
      return function(end: boolean | null, cb: (end: boolean | null, data?: number) => void) {
        if (end) return cb(end);
        if (i >= values.length) return cb(true);
        cb(null, values[i++]);
      };
    })();

    // Create a through object that doubles values
    const doubler = createThrough((x) => x * 2);

    // Use pull with the through object - this should work with original code
    // but fail with mutated code since the else if (s && typeof s === 'object') branch is disabled
    const result = pull(sourceStream, doubler);
    sink(result);
  });
});
```
